```rust
// fuzz/fuzz_targets/decrypt.rs
#![no_main]

use libfuzzer_sys::fuzz_target;
use arbitrary::Arbitrary;
use coding_agent_search::export::crypto::{decrypt_with_password, KeySlot};

#[derive(Arbitrary, Debug)]
struct DecryptInput {
    ciphertext: Vec<u8>,
    password: String,
    salt: [u8; 16],
    nonce_prefix: [u8; 4],
    kdf_m_cost: u32,
    kdf_t_cost: u32,
    kdf_p_cost: u32,
}

fuzz_target!(|input: DecryptInput| {
    // Clamp KDF params to reasonable ranges to avoid OOM
    let m_cost = (input.kdf_m_cost % 65536).max(1024);
    let t_cost = (input.kdf_t_cost % 4).max(1);
    let p_cost = (input.kdf_p_cost % 4).max(1);

    let key_slot = KeySlot {
        kdf: "argon2id".to_string(),
        kdf_params: serde_json::json!({
            "m_cost": m_cost,
            "t_cost": t_cost,
            "p_cost": p_cost,
            "salt": base64::encode(&input.salt),
        }),
        encrypted_dek: vec![0u8; 48], // 32 byte key + 16 byte tag
        nonce_prefix: input.nonce_prefix.to_vec(),
    };

    // This should never panic, only return errors
    let _ = decrypt_with_password(
        &input.ciphertext,
        &input.password,
        &key_slot,
    );
});
```

### 2. KDF Fuzzer
